<?phpnamespace App\Controller;use App\Entity\SysAdminOperation;use App\Entity\TypeAcquisition;use App\Form\TypeAcquisitionType;use App\Repository\TypeAcquisitionRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class TypeAcquisitionController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/type-acquisitions", name="type_acquisition_index", methods={"GET"})     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @return Response     */    public function index(TypeAcquisitionRepository $typeAcquisitionRepository): Response    {        return $this->render('type_acquisition/index.html.twig', [            'type_acquisitions' => $typeAcquisitionRepository->findAll()        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-acquisitions/new", name="type_acquisition_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws Exception     */    public function new(Request $request): Response    {        $typeAcquisition = new TypeAcquisition();        $form = $this->createForm(TypeAcquisitionType::class, $typeAcquisition);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($typeAcquisition);            $entityManager->flush();            $this->addFlash('success', 'Le type acquisition a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement type acquisition')                ->setUserAffected($typeAcquisition->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('type_acquisition_index');        }        return $this->render('type_acquisition/new.html.twig', [            'type_acquisition' => $typeAcquisition,            'form' => $form->createView(),        ]);    }    /**     * @Route("/super-admin/type-acquisitions/{id}", name="type_acquisition_show", methods={"GET"})     * @param TypeAcquisition $typeAcquisition     * @return Response     */    public function show(TypeAcquisition $typeAcquisition): Response    {        return $this->render('type_acquisition/show.html.twig', [            'type_acquisition' => $typeAcquisition,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-acquisitions/{id}/edit", name="type_acquisition_edit", methods={"GET","POST"})     * @param Request $request     * @param TypeAcquisition $typeAcquisition     * @return Response     * @throws Exception     */    public function edit(Request $request, TypeAcquisition $typeAcquisition): Response    {        $form = $this->createForm(TypeAcquisitionType::class, $typeAcquisition);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type acquisition a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification type acquisition')                ->setUserAffected($typeAcquisition->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('type_acquisition_index');        }        return $this->render('type_acquisition/edit.html.twig', [            'type_acquisition' => $typeAcquisition,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-acquisitions/{id}", name="type_acquisition_delete", methods={"DELETE"})     * @param Request $request     * @param TypeAcquisition $typeAcquisition     * @return Response     * @throws Exception     */    public function delete(Request $request, TypeAcquisition $typeAcquisition): Response    {        if ($this->isCsrfTokenValid('delete' . $typeAcquisition->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($typeAcquisition);            $entityManager->flush();            $this->addFlash('success', 'Le type acquisition a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression type acquisition')                ->setUserAffected($typeAcquisition->getName());            $entityManager->persist($sysOp);            $entityManager->flush();        }        return $this->redirectToRoute('type_acquisition_index');    }    /**     * @Route("koh_archivage/admin/type_acquisitions/get_type_acquisition")     * @param TypeAcquisitionRepository $aquisitionRepository     * @return JsonResponse     */    public function load_type_acquition(TypeAcquisitionRepository $aquisitionRepository): JsonResponse    {        $types = $aquisitionRepository->findAll();        $array_type = array();        foreach ($types as $type) {            $t = array(                'id' => $type->getId(),                'libelle' => $type->getName()            );            $array_type[] = $t;        }        return new JsonResponse($array_type, 200);    }    /**     * @Route("/koh/type-acquisition/get/{id}", name="type_acquisition.get", methods={"GET"})     * @param TypeAcquisition $typeAcquisition     * @return JsonResponse     */    public function getType(TypeAcquisition $typeAcquisition): JsonResponse    {        $result = array(            'id' => $typeAcquisition->getId(),            'libelle' => $typeAcquisition->getName(),            'isBienForStructure' => $typeAcquisition->getIsBienForStructure()        );        return new JsonResponse($result, 200);    }}